// ng-dev/misc/generated-files/update-generated-files.js
async function updateGeneratedFileTargets() {
  const spinner = new Spinner("Querying for all generated file targets");
  try {
    const result = await ChildProcess.spawn(getBazelBin(), [
      "query",
      `kind(esbuild, //...) intersect attr(name, '_generated$', //...)`,
      "--output",
      "label"
    ], { mode: "silent" });
    if (result.status !== 0) {
      throw new Error(`Unexpected error: ${result.stderr}`);
    }
    const targets = result.stdout.trim().split(/\r?\n/).map((x) => x.replace(/_generated$/, ""));
    Log.debug("Discovered Targets");
    targets.forEach((target) => Log.debug(target));
    spinner.update(`Found ${targets.length} generated file targets to update`);
    await ChildProcess.spawn(getBazelBin(), ["build", ...targets], { mode: "silent" });
    for (let idx = 0; idx < targets.length; idx++) {
      const target = targets[idx];
      spinner.update(`${idx + 1} of ${targets.length} updates completed`);
      const updateResult = await ChildProcess.spawn(getBazelBin(), ["run", target], {
        mode: "silent"
      });
      if (updateResult.status !== 0) {
        throw new Error(`Unexpected error while updating: ${target}.`);
      }
    }
    spinner.complete();
    Log.info(` ${green("\u2714")}  Updated all generated files (${targets.length} targets)`);
  } catch (e) {
    spinner.failure("An error has occurred.");
    throw e;
  }
}

// ng-dev/misc/generated-files/cli.js
async function builder12(argv) {
  return argv;
}
async function handler12() {
  await updateGeneratedFileTargets();
}
var GeneratedFilesModule = {
  builder: builder12,
  handler: handler12,
  command: "update-generated-files",
  describe: "Automatically discover all bazel generated file targets and update them."
};

